/**
 * Calculates the partner payout for a transaction.
 *
 * Formula:
 *   platformFeeAmount = transactionAmount * platformFeePercentage
 *   payout = (transactionAmount - platformFeeAmount) * partnerSharePercentage
 *   result is floored to the nearest cent to avoid overpaying partners.
 *
 * @param transactionAmount      - Gross transaction amount in dollars (float)
 * @param platformFeePercentage  - Platform fee as a decimal (e.g. 0.05 = 5%)
 * @param partnerSharePercentage - Partner share as a decimal (e.g. 0.70 = 70%)
 * @returns Partner payout in dollars, floored to the nearest cent
 */
export function calculatePartnerPayout(
  transactionAmount: number,
  platformFeePercentage: number,
  partnerSharePercentage: number
): number {
  const platformFeeAmount = transactionAmount * platformFeePercentage;
  const netAmount = transactionAmount - platformFeeAmount;
  const rawPayout = netAmount * partnerSharePercentage;

  // Floor to nearest cent (avoid overpaying partners on fractional cents)
  return Math.floor(rawPayout * 100) / 100;
}

